    const CHAT_SCOPED_CONFIG_VERSION_ACU = 1;
    /** Sheet Guide（空白指导表）的字段名 */
    const CHAT_SHEET_GUIDE_FIELD_ACU = 'TavernDB_ACU_InternalSheetGuide';
    /** Sheet Guide 版本号（v2 新增 seedRows） */
    const CHAT_SHEET_GUIDE_VERSION_ACU = 2;
