        // 交火/向量模型 API 配置是全局配置，权威副本存放在 globalMeta.vectorMemoryConfigGlobal。
        // profile payload 中继续保存会导致切换隔离标识后旧值反向污染全局配置。
        delete cloned.vectorMemoryConfig;
